def verify(workspace_path, external_services_path=None):
    # Try to find the match log file with flexible matching
    xlsx_files = list(Path(workspace_path).glob('match_log_2026_Q2.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('*.xlsx') if 'match' in f.name.lower() and 'log' in f.name.lower()]
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).glob('*.xlsx') if 'match' in f.name.lower()]
    if not xlsx_files:
        # Also search subdirectories
        xlsx_files = list(Path(workspace_path).rglob('match_log_2026_Q2.xlsx'))
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).rglob('*.xlsx') if 'match' in f.name.lower() and 'log' in f.name.lower()]
    if not xlsx_files:
        xlsx_files = [f for f in Path(workspace_path).rglob('*.xlsx') if 'match' in f.name.lower()]
    if not xlsx_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'match_log_2026_Q2.xlsx not found in workspace'}

    wb = openpyxl.load_workbook(xlsx_files[0])
    ws = wb.active
    if len(wb.sheetnames) > 1:
        for name in wb.sheetnames:
            if 'match' in name.lower() or 'log' in name.lower() or '2026' in name:
                ws = wb[name]
                break

    # Parse headers flexibly
    headers = {}
    for col in range(1, ws.max_column + 1):
        val = ws.cell(row=1, column=col).value
        if val:
            headers[str(val).strip().lower()] = col

    inv_id_col = None
    date_col = None
    result_col = None

    for h, c in headers.items():
        if 'invoice' in h and 'id' in h:
            inv_id_col = c
        elif h in ('inv id', 'id', 'invoice_id', 'inv_id', 'invoiceid') and inv_id_col is None:
            inv_id_col = c
        if 'match' in h and 'date' in h:
            date_col = c
        elif 'date' in h and date_col is None:
            date_col = c
        if 'match' in h and ('result' in h or 'status' in h):
            result_col = c
        elif ('result' in h or 'status' in h) and result_col is None:
            result_col = c

    if inv_id_col is None:
        inv_id_col = 1

    if date_col is None or result_col is None:
        return {'pass': False, 'score': 0.0, 'feedback': f'Required columns not found. Headers found: {list(headers.keys())}'}

    # The rubric requires these four invoices with Match Date 2026-04-08 and Match Result containing "PASS"
    expected_invoices = {'INV-018', 'INV-021', 'INV-024', 'INV-026'}

    found = {}
    for row in range(2, ws.max_row + 1):
        inv_val = ws.cell(row=row, column=inv_id_col).value
        if inv_val and str(inv_val).strip() in expected_invoices:
            inv_id = str(inv_val).strip()
            date_val = ws.cell(row=row, column=date_col).value
            result_val = ws.cell(row=row, column=result_col).value
            found[inv_id] = {'date': date_val, 'result': result_val, 'row': row}

    missing = expected_invoices - set(found.keys())
    if missing:
        return {'pass': False, 'score': 0.0, 'feedback': f'Invoice IDs missing from match log: {sorted(missing)}'}

    def check_date(val):
        if val is None:
            return False
        if isinstance(val, datetime):
            return val.date() == date(2026, 4, 8)
        if isinstance(val, date):
            return val == date(2026, 4, 8)
        s = str(val).strip()
        return ('2026-04-08' in s or '04/08/2026' in s or '04-08-2026' in s or
                '2026/04/08' in s or 'april 8' in s.lower() or 'apr 8' in s.lower() or
                '8 apr' in s.lower() or '8 april' in s.lower() or
                '4/8/2026' in s or '8/4/2026' in s or '2026.04.08' in s)

    def check_result_contains_pass(val):
        """Rubric says Match Result must contain the word PASS."""
        if val is None:
            return False
        result_str = str(val).strip().upper()
        # Check if the word PASS appears anywhere in the result string
        # This is intentionally loose: PASS, MATCH-PASS, MATCH_PASS, MATCH PASS, 3-Way Pass, etc.
        return 'PASS' in result_str

    failures = []
    for inv_id in sorted(expected_invoices):
        actual = found[inv_id]
        if not check_date(actual['date']):
            failures.append(f'{inv_id} (row {actual["row"]}): Match Date={actual["date"]} (expected 2026-04-08)')
        if not check_result_contains_pass(actual['result']):
            failures.append(f'{inv_id} (row {actual["row"]}): Match Result={actual["result"]} (expected to contain the word PASS)')

    if failures:
        return {'pass': False, 'score': 0.0, 'feedback': 'Match log failures: ' + '; '.join(failures)}

    # Collect actual values for detailed feedback
    details = []
    for inv_id in sorted(expected_invoices):
        actual = found[inv_id]
        details.append(f'{inv_id}: date={actual["date"]}, result={actual["result"]}')

    return {'pass': True, 'score': 1.0, 'feedback': f'All required invoices (INV-018, INV-021, INV-024, INV-026) found in match log with Match Date 2026-04-08 and Match Result containing PASS. Details: ' + '; '.join(details)}
